from typing import List

class Solution:
    def grayCode(self, n: int) -> List[int]:
        if n == 0:
            return [0]

        gray_code = [0, 1]
        for i in range(1, n):
            gray_code = gray_code + [(1 << i) + x for x in reversed(gray_code)]

        return gray_code
